_NuFrRa_async function (s, r) {
    let i = s.find(e => e.includes(":")),
        n = s.find(e => /^-.*n.*/.test(e)),
        o;
    return i ? o = await r("dscl . -list /Groups PrimaryGroupID | tr -s ' '| sort -r") : o = await r("dscl . -list /Users UniqueID | tr -s ' '| sort -r"), o.split("\n").map(e => e.split(" ")).map(e => ({
      name: n ? e[1] : e[0],
      description: i ? "Group - ".concat(n ? e[0] : "gid: ".concat(e[1])) : "User - ".concat(n ? e[0] : "uid: ".concat(e[1])),
      icon: i ? "\u{1F465}" : "\u{1F464}",
      priority: 90
    }));
  }
